		var fine = Services.getValue(EnterFineAmount.dataBinding);
		var maxVal = 99999.99;	
		var err = null;
      	if( '0.00 ' != fine )
	  	{   err = validateCurrencyValue(fine, maxVal);
	      	if( null == err)
	      	{ 
	      		var returnVal = WPU.formatToTwoDP(fine);
		    	Services.setValue(EnterFineAmount.dataBinding, returnVal);
	      	}	
	  	}
		return err;

