function DefaultCurrency823() {}
DefaultCurrency823.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency823.tabIndex = -1;
DefaultCurrency823.maxLength = 1;
DefaultCurrency823.isReadOnly = function(){return true;}
DefaultCurrency823.isTemporary = function(){return true;}
DefaultCurrency823.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency823.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
